	context "context"
	unionsgo "github.com/fern-api/unions-go"
	unionsgoclient "github.com/fern-api/unions-go/client"
)

client := unionsgoclient.NewClient()
response, err := client.Union.Update(
	context.TODO(),
	&unionsgo.Shape{
